import{_ as e,o as a,c as l,a2 as i}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"F18: 合理估值與決策綜合判斷 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6261_久元/20260424/F18_合理估值與決策綜合判斷_投資研究員.md","filePath":"審計報告庫/財務審計/6261_久元/20260424/F18_合理估值與決策綜合判斷_投資研究員.md"}'),r={name:"審計報告庫/財務審計/6261_久元/20260424/F18_合理估值與決策綜合判斷_投資研究員.md"};function n(o,t,s,d,h,x){return a(),l("div",null,[...t[0]||(t[0]=[i('<h1 id="f18-合理估值與決策綜合判斷-投資研究員-審計報告" tabindex="-1">F18: 合理估值與決策綜合判斷 - 投資研究員 審計報告 <a class="header-anchor" href="#f18-合理估值與決策綜合判斷-投資研究員-審計報告" aria-label="Permalink to &quot;F18: 合理估值與決策綜合判斷 - 投資研究員 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>綜合此前之財務、治理與籌碼事實，進行極端情境下的壓力測試，判定在最差預期下股價的防禦位階。結合本益比河流圖建立價格邊界，判定當下投入的風險回報比，給出具備實戰強度的投資對策。</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>風險點為：(1) 獲利成長動能平緩（FY2025 EPS 4.24 元，年增僅 4.2%）、(2) 外資 4 月下旬出現連續淨賣超。願景實現度為中偏低（高配息率 94-98% 壓縮再投資空間）。目前估值落於河流圖 35% 分位（PER 14.8x），略低於歷史中位數 15x，未達極端低估但具備基本安全邊際。合理買進價位 51-55 元（12-13x PER），目標價 76-85 元（18-20x PER），風險回報比約 1.8:1。決策等級 A（良），戰術建議為分批佈局於 55 元以下，停損設於 46 元。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>評級：A（良）</strong></p><p>關鍵數據基石：</p><ul><li>當前股價（推估）：約 60-63 元（PER 14.8x / PBR 1.15x）</li><li>每股淨值（BPS, 2025Q4）：51.9 元 → PBR 1.15 倍，低於歷史中位數 1.30x</li><li>歷史 PER 區間：12x（底部）～ 20x（頂部），中位數 15x</li><li>當前 PER 百分位數：35%（低於中位數，具有安全邊際）</li><li>TTM EPS（2025 全年）：4.24 元</li><li>現金股利：4.0 元（配息率 94-98%，殖利率 6.66%）</li><li>營收 FY2025：39.55 億（YoY +—1.2%），成長動能平緩</li><li>FY2026 Q1（2026/01-03）累計營收：10.06 億（YoY +5.8%），動能略回升</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="_1-風險壓力測試-risk-stress-test" tabindex="-1">1. 風險壓力測試（Risk Stress Test） <a class="header-anchor" href="#_1-風險壓力測試-risk-stress-test" aria-label="Permalink to &quot;1. 風險壓力測試（Risk Stress Test）&quot;">​</a></h3><p><strong>情境一：營收衰退 20%</strong> 若半導體景氣下行導致營收縮減 20%，以久元 FY2025 年約 25% 的毛利率估算，EPS 可能降至 3.2-3.4 元。搭配歷史底部 PER 12x，股價物理支撐位約 38-41 元。從當前 63 元計，最大下檔空間約 37-40%。</p><p><strong>情境二：配息縮水</strong> 若因現金需求或獲利衰退導致配息從 4.0 元降至 3.0 元（配息率仍高於 80%），以高殖利率防禦股慣例 5-6% 殖利率回推，合理價位為 50-60 元，與當前接近。</p><p><strong>情境三：極端市場賣壓</strong> 若大戶鎖倉鬆動（千張大戶從 34.5% 降至 28%），以過去三年最低 PBR 1.07 倍 × BPS 51.9 元 = 55.5 元支撐。結合前述 EPS 風險情境，最惡劣情況約 38-46 元。</p><h3 id="_2-評價位階對位-valuation-anchoring" tabindex="-1">2. 評價位階對位（Valuation Anchoring） <a class="header-anchor" href="#_2-評價位階對位-valuation-anchoring" aria-label="Permalink to &quot;2. 評價位階對位（Valuation Anchoring）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">倍數</th><th style="text-align:left;">對應股價</th><th style="text-align:left;">距當前</th><th style="text-align:left;">位階判定</th></tr></thead><tbody><tr><td style="text-align:left;">12x PER（底部）</td><td style="text-align:left;">50.9 元</td><td style="text-align:left;">-19.0%</td><td style="text-align:left;">強力買進區</td></tr><tr><td style="text-align:left;">14x PER</td><td style="text-align:left;">59.4 元</td><td style="text-align:left;">-5.5%</td><td style="text-align:left;">分批佈局區</td></tr><tr><td style="text-align:left;"><strong>15x PER（中位數）</strong></td><td style="text-align:left;"><strong>63.6 元</strong></td><td style="text-align:left;"><strong>+1.3%</strong></td><td style="text-align:left;"><strong>合理價位</strong></td></tr><tr><td style="text-align:left;">18x PER</td><td style="text-align:left;">76.3 元</td><td style="text-align:left;">+21.5%</td><td style="text-align:left;">偏高區</td></tr><tr><td style="text-align:left;">20x PER（頂部）</td><td style="text-align:left;">84.8 元</td><td style="text-align:left;">+35.0%</td><td style="text-align:left;">賣出區</td></tr></tbody></table><p>當前 PBR 1.15x 處於歷史 20-25% 分位（中位數 1.30x，頂部 1.60x），從資產價值角度同樣具備低估特徵。</p><h3 id="_3-願景真偽審核" tabindex="-1">3. 願景真偽審核 <a class="header-anchor" href="#_3-願景真偽審核" aria-label="Permalink to &quot;3. 願景真偽審核&quot;">​</a></h3><p>久元的策略路線為「鞏固代工本業 + 高配息回饋股東」。FY2025 資本支出達 9.83 億（年增 161%），但研發費用約僅營收 1-2%，顯示公司選擇「產能擴張」而非「技術研發」路線。此策略的好處是營收規模可望增長，但缺點是缺乏差異化競爭力，長期毛利率不易突破。</p><p><strong>判定：願景保守但務實，操作價值有限但防禦性強。</strong></p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><h3 id="便宜的理由-vs-壞掉的真相" tabindex="-1">便宜的理由 vs 壞掉的真相 <a class="header-anchor" href="#便宜的理由-vs-壞掉的真相" aria-label="Permalink to &quot;便宜的理由 vs 壞掉的真相&quot;">​</a></h3><p>久元屬於「便宜的景氣循環週期股」，而非「結構性衰退的價值陷阱」：</p><ul><li><strong>便宜的理由</strong>：PER 14.8x 低於中位數 15x，PBR 1.15x 僅歷史 25% 分位，搭配 6.66% 殖利率與零負債，是典型的高殖利率防禦型低估標的</li><li><strong>不是壞掉的真相</strong>：負債比 18%、淨現金 14 億、無董監質押、大戶持續鎖碼，財務面無結構性瑕疵</li></ul><h3 id="安全邊際判定" tabindex="-1">安全邊際判定 <a class="header-anchor" href="#安全邊際判定" aria-label="Permalink to &quot;安全邊際判定&quot;">​</a></h3><p>以當前 63 元 vs 合理價 63.6 元（15x PER），安全邊際趨近於零。真正的安全邊際存在於 51-55 元區間（12-13x PER）。以當前的成長動能（EPS 年增 4%）和 PEG 3.7x 來看，成長性無法支撐更高溢價。</p><h3 id="最終執行建議" tabindex="-1">最終執行建議 <a class="header-anchor" href="#最終執行建議" aria-label="Permalink to &quot;最終執行建議&quot;">​</a></h3><ul><li><strong>買進價位</strong>：55 元以下（12.5-13x PER）分批佈局</li><li><strong>合理目標</strong>：76 元（18x PER，約河流圖上 70% 分位）</li><li><strong>停損防線</strong>：46 元（跌破 FY2024 低點 PER 12x 並進一步惡化）</li><li><strong>操作戰術</strong>：股息回收型——以 55 元買進，4 元股息 = 7.3% 殖利率，即使股價不漲，3 年可回收 21.9%</li><li><strong>不建議追高於 65 元以上</strong>，因安全邊際已消失且外資出現賣壓訊號</li></ul><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><code>數據採集器查詢</code>: per 6261 2023-04-24 2026-04-24 (科目：PER/PBR/殖利率)</li><li><code>數據採集器查詢</code>: balance_sheet 6261 2023-04-24 2026-04-24 (科目：每股淨值計算)</li><li><code>數據採集器查詢</code>: finance 6261 2023-04-24 2026-04-24 (科目：EPS 各季/年度)</li><li><code>數據採集器查詢</code>: revenue 6261 2023-04-24 2026-04-24 (科目：月營收趨勢)</li><li><code>物理數值校準</code>：已確認當前 PER 14.8x 及 PBR 1.15x 為 2026/04/24 最新數據</li><li><code>物理數值校準</code>：已確認 2025Q4 BPS 51.9 元由歸屬母公司權益 / 發行股數計算</li></ul>',30)])])}const _=e(r,[["render",n]]);export{c as __pageData,_ as default};
